parameters.jsCode:
// Normalise input from webhook or manual trigger
const body = $input.first().json.body || $input.first().json;

const transcript = body.transcript ||
  body.text ||
  'No transcript provided — please pass { transcript: "..." }';

const interview = {
  id:           body.id           || `int_${Date.now()}`,
  participant:  body.participant  || 'Anonymous',
  role:         body.role         || 'Unknown',
  company:      body.company      || 'Unknown',
  segment:      body.segment      || 'Unknown',
  date:         body.date         || new Date().toISOString().slice(0,10),
  duration_min: body.duration_min || null,
  interviewer:  body.interviewer  || 'Unknown',
  transcript:   transcript.slice(0, 15000), // max 15k chars to control AI cost
  source:       body.source       || 'webhook',
};

return [{ json: interview }];

values.content:
Extract research artefacts from this interview transcript.

Participant: {{ $json.participant }}
Role: {{ $json.role }}
Company: {{ $json.company }}
Segment: {{ $json.segment }}
Date: {{ $json.date }}

Transcript:
{{ $json.transcript }}

Return a JSON object with these exact keys:
{
  "problems": [{"text": str, "quote": str, "frequency": "one-off|recurring", "severity": "low|medium|high|critical"}],
  "motivations": [{"text": str, "quote": str}],
  "current_alternatives": [{"name": str, "why_used": str, "why_inadequate": str}],
  "key_quotes": [{"text": str, "context": str, "theme": str}],
  "objections": [{"text": str, "quote": str}],
  "opportunities": [{"text": str, "confidence": "low|medium|high", "evidence": str}],
  "segment_signals": [{"signal": str, "implication": str}],
  "recommended_follow_ups": [str],
  "overall_sentiment": "very_negative|negative|neutral|positive|very_positive",
  "themes": [str]
}

parameters.jsCode:
const interview = $('Normalise Input').first().json;
let artefacts;
try {
  const raw = $input.first().json.message?.content ||
              $input.first().json.content || '{}';
  artefacts = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch (e) {
  artefacts = { _parse_error: e.message, _raw: $input.first().json };
}

return [{
  json: {
    interview_id:  interview.id,
    participant:   interview.participant,
    role:          interview.role,
    company:       interview.company,
    segment:       interview.segment,
    date:          interview.date,
    processed_at:  new Date().toISOString(),
    artefacts,
    evidence_link: `Source: interview with ${interview.participant} on ${interview.date}`,
  }
}];
